async function getSequential() {
  const user = await fetchUser();      // Wait 1 second
  const posts = await fetchPosts();    // Wait 1 second
  const comments = await fetchComments(); // Wait 1 second
  // Total time: 3 seconds
}

async function getParallel() {
  const [user, posts, comments] = await Promise.all([
    fetchUser(),
    fetchPosts(),
    fetchComments()
  ]);
  // Total time: 1 second (all happen simultaneously)
}

async function getWithErrors() {
  const results = await Promise.allSettled([
    fetchUser(),
    fetchPosts(),
    fetchComments()
  ]);

  results.forEach((result, index) => {
    if (result.status === 'fulfilled') {
      console.log(`Request ${index} succeeded:`, result.value);
    } else {
      console.log(`Request ${index} failed:`, result.reason);
    }
  });
}

